/**
 * Device Adapter Architecture - Type Definitions
 * 
 * Defines the interfaces for integrating third-party ophthalmic devices
 * (Zeiss OCT, Heidelberg Spectralis, Topcon, etc.)
 */

/** Adapter type identifiers */
export type AdapterType = 'dicom' | 'rest' | 'file' | 'custom';

/** Runtime status of an adapter */
export type AdapterStatus = 'idle' | 'starting' | 'running' | 'stopping' | 'error' | 'disabled';

/** Events emitted by adapters */
export type AdapterEventType =
  | 'image:received'
  | 'image:error'
  | 'adapter:started'
  | 'adapter:stopped'
  | 'adapter:error'
  | 'adapter:status';

/** Lightweight typed event emitter */
export class AdapterEventEmitter {
  private listeners = new Map<string, Set<(data: any) => void>>();

  on(event: AdapterEventType, listener: (data: any) => void): () => void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    this.listeners.get(event)!.add(listener);
    return () => this.off(event, listener);
  }

  off(event: AdapterEventType, listener: (data: any) => void): void {
    this.listeners.get(event)?.delete(listener);
  }

  emit(event: AdapterEventType, data: any): void {
    this.listeners.get(event)?.forEach((fn) => {
      try {
        fn(data);
      } catch (err) {
        console.error(`[AdapterEvent] Error in listener for ${event}:`, err);
      }
    });
  }

  removeAllListeners(event?: AdapterEventType): void {
    if (event) {
      this.listeners.delete(event);
    } else {
      this.listeners.clear();
    }
  }
}

/** Shape of an image received from a device */
export interface InboundImageData {
  /** Raw file bytes */
  buffer: Buffer;
  /** Original filename if available */
  filename?: string;
  /** MIME type or file extension */
  format: string;
  /** DICOM metadata or device-specific metadata */
  metadata: Record<string, unknown>;
}

/** Metadata extracted from a received image */
export interface ImageMetadata {
  patientMrn?: string;
  patientName?: string;
  studyDate?: string;
  studyTime?: string;
  studyInstanceUid?: string;
  seriesInstanceUid?: string;
  sopInstanceUid?: string;
  modality?: string;
  bodyPart?: string;
  laterality?: 'L' | 'R' | 'both';
  manufacturer?: string;
  modelName?: string;
  width?: number;
  height?: number;
  bitsAllocated?: number;
  /** Device-specific extra fields */
  extra?: Record<string, unknown>;
}

/** Patient query criteria */
export interface PatientCriteria {
  mrn?: string;
  name?: string;
  birthDate?: string;
}

/** Simplified patient info returned by query */
export interface PatientQueryResult {
  mrn: string;
  name: string;
  birthDate?: string;
  gender?: string;
}

/** Study query criteria */
export interface StudyCriteria {
  patientMrn?: string;
  studyDate?: string;
  modality?: string;
  studyInstanceUid?: string;
}

/** Simplified study info returned by query */
export interface StudyQueryResult {
  studyInstanceUid: string;
  patientMrn: string;
  studyDate: string;
  modality: string;
  description?: string;
  seriesCount?: number;
}

/** Connection / operational status snapshot */
export interface AdapterStatusInfo {
  id: string;
  name: string;
  type: AdapterType;
  status: AdapterStatus;
  lastError?: string;
  lastImageAt?: string;
  imageCount: number;
  uptime: number; // ms since last start
  config: Record<string, unknown>; // sanitized config (no secrets)
}

/** Configuration block passed to an adapter on init */
export interface AdapterConfig {
  /** Unique adapter instance id (assigned by registry) */
  id: string;
  /** Human-readable name */
  name: string;
  /** Adapter type */
  type: AdapterType;
  /** Whether the adapter is enabled */
  enabled: boolean;

  // DICOM-specific
  dicom?: {
    /** Our AE Title (SCP) */
    aeTitle: string;
    /** Listening port for C-STORE SCP */
    port: number;
    /** Max concurrent associations */
    maxAssociations?: number;
    /** Supported transfer syntaxes (UID list) */
    transferSyntaxes?: string[];
  };

  // REST-specific
  rest?: {
    /** Base URL of the external system to call */
    endpoint?: string;
    /** API key for authenticating inbound uploads */
    apiKey?: string;
    /** Webhook URL we call when an image is received */
    webhookUrl?: string;
    /** Webhook secret for HMAC verification */
    webhookSecret?: string;
  };

  // File-system / custom
  file?: {
    /** Directory to watch for incoming files */
    watchPath: string;
    /** Glob pattern for files to pick up */
    pattern?: string;
    /** Whether to delete files after import */
    deleteAfterImport?: boolean;
  };

  /** Opaque user-defined config for custom adapters */
  custom?: Record<string, unknown>;
}

/** The core adapter interface every device adapter must implement */
export interface DeviceAdapter {
  /** Unique id (set by registry from config) */
  readonly id: string;
  /** Human-readable name */
  readonly name: string;
  /** Adapter type */
  readonly type: AdapterType;

  /** Current runtime status */
  readonly status: AdapterStatus;

  /** Typed event bus */
  readonly events: AdapterEventEmitter;

  /**
   * Prepare the adapter for operation.
   * Must be called exactly once before start().
   */
  initialize(config: AdapterConfig): Promise<void>;

  /** Begin accepting / pulling images. */
  start(): Promise<void>;

  /** Gracefully stop. No more images after this returns. */
  stop(): Promise<void>;

  /** Destroy the adapter, releasing all resources. */
  destroy(): Promise<void>;

  /** Get a status snapshot. */
  getStatus(): AdapterStatusInfo;

  /**
   * Push an image into the system via this adapter.
   * (Used by REST adapter receiving uploads, or file adapter.)
   */
  receiveImage(image: InboundImageData): Promise<void>;

  /**
   * Query patients visible to this adapter / device.
   * Returns empty array if not supported.
   */
  queryPatient(criteria: PatientCriteria): Promise<PatientQueryResult[]>;

  /**
   * Query studies visible to this adapter / device.
   * Returns empty array if not supported.
   */
  queryStudies(criteria: StudyCriteria): Promise<StudyQueryResult[]>;
}

/**
 * Base Adapter - Abstract base class with common lifecycle logic.
 * 
 * Concrete adapters (DICOM, REST, File, Custom) extend this class.
 */

import { v4 as uuid } from 'uuid';
import {
  type AdapterConfig,
  type AdapterStatus,
  type AdapterStatusInfo,
  type AdapterType,
  type DeviceAdapter,
  type InboundImageData,
  type PatientCriteria,
  type PatientQueryResult,
  type StudyCriteria,
  type StudyQueryResult,
  AdapterEventEmitter,
} from './types';

export abstract class BaseAdapter implements DeviceAdapter {
  readonly id: string;
  readonly name: string;
  readonly type: AdapterType;
  readonly events = new AdapterEventEmitter();

  protected config!: AdapterConfig;
  protected _status: AdapterStatus = 'idle';
  protected _lastError?: string;
  protected _lastImageAt?: string;
  protected _imageCount = 0;
  protected _startedAt?: number;

  constructor(type: AdapterType, id?: string) {
    this.type = type;
    this.id = id ?? uuid();
    this.name = '';
  }

  get status(): AdapterStatus {
    return this._status;
  }

  /** Hook: called during initialize() after config is stored. */
  protected abstract onInitialize(config: AdapterConfig): Promise<void>;

  /** Hook: called during start() */
  protected abstract onStart(): Promise<void>;

  /** Hook: called during stop() */
  protected abstract onStop(): Promise<void>;

  /** Hook: called during destroy() */
  protected abstract onDestroy(): Promise<void>;

  async initialize(config: AdapterConfig): Promise<void> {
    if (this._status !== 'idle' && this._status !== 'disabled') {
      throw new Error(
        `[${this.id}] Cannot initialize adapter in status "${this._status}"`,
      );
    }
    this.config = config;
    // Apply name from config; subclasses can override in onInitialize.
    (this as any).name = config.name;
    this._setStatus('idle');
    await this.onInitialize(config);
  }

  async start(): Promise<void> {
    if (this._status === 'running') return;
    if (this._status !== 'idle' && this._status !== 'disabled') {
      throw new Error(
        `[${this.id}] Cannot start adapter in status "${this._status}"`,
      );
    }
    this._setStatus('starting');
    try {
      await this.onStart();
      this._startedAt = Date.now();
      this._setStatus('running');
      this.events.emit('adapter:started', { id: this.id });
    } catch (err) {
      this._lastError = err instanceof Error ? err.message : String(err);
      this._setStatus('error');
      this.events.emit('adapter:error', { id: this.id, error: this._lastError });
      throw err;
    }
  }

  async stop(): Promise<void> {
    if (this._status !== 'running') return;
    this._setStatus('stopping');
    try {
      await this.onStop();
      this._startedAt = undefined;
      this._setStatus('idle');
      this.events.emit('adapter:stopped', { id: this.id });
    } catch (err) {
      this._lastError = err instanceof Error ? err.message : String(err);
      this._setStatus('error');
      this.events.emit('adapter:error', { id: this.id, error: this._lastError });
      throw err;
    }
  }

  async destroy(): Promise<void> {
    if (this._status === 'running') {
      await this.stop();
    }
    await this.onDestroy();
    this.events.removeAllListeners();
    this._setStatus('disabled');
  }

  getStatus(): AdapterStatusInfo {
    return {
      id: this.id,
      name: this.config?.name ?? this.name,
      type: this.type,
      status: this._status,
      lastError: this._lastError,
      lastImageAt: this._lastImageAt,
      imageCount: this._imageCount,
      uptime: this._startedAt ? Date.now() - this._startedAt : 0,
      config: this.sanitizeConfig(),
    };
  }

  async receiveImage(image: InboundImageData): Promise<void> {
    if (this._status !== 'running') {
      throw new Error(
        `[${this.id}] Adapter is not running (status: ${this._status})`,
      );
    }
    this._lastImageAt = new Date().toISOString();
    this._imageCount++;
  }

  async queryPatient(_criteria: PatientCriteria): Promise<PatientQueryResult[]> {
    return [];
  }

  async queryStudies(_criteria: StudyCriteria): Promise<StudyQueryResult[]> {
    return [];
  }

  // ── Helpers ───────────────────────────────────────────────────────────────────

  protected _setStatus(status: AdapterStatus): void {
    this._status = status;
    this.events.emit('adapter:status', { id: this.id, status });
  }

  /** Strip secrets from config before exposing via getStatus(). */
  protected sanitizeConfig(): Record<string, unknown> {
    if (!this.config) return {};
    const { rest, ...restConfig } = this.config;
    const safeRest = rest
      ? { ...rest, apiKey: rest.apiKey ? '***' : undefined, webhookSecret: rest.webhookSecret ? '***' : undefined }
      : undefined;
    return { ...restConfig, rest: safeRest };
  }
}

/**
 * Adapter Registry - Lifecycle management for all device adapters.
 *
 * Provides:
 *  - Registration of adapter classes or instances
 *  - Start / stop / status management
 *  - Hot-reload support (stop old → init new → start)
 *  - Singleton access via `getRegistry()`
 */

import { v4 as uuid } from 'uuid';
import {
  type AdapterConfig,
  type AdapterStatusInfo,
  type AdapterType,
  type DeviceAdapter,
} from './types';

/** Factory function: receives config, returns a ready-to-init adapter instance */
export type AdapterFactory = (config: AdapterConfig) => DeviceAdapter;

interface RegistryEntry {
  config: AdapterConfig;
  adapter: DeviceAdapter;
}

class AdapterRegistry {
  private entries = new Map<string, RegistryEntry>();
  private factories = new Map<AdapterType, AdapterFactory>();

  // ── Factory registration ─────────────────────────────────────────────────────

  /**
   * Register a factory for an adapter type.
   * When adapters of this type are added, the factory is called to create the instance.
   */
  registerFactory(type: AdapterType, factory: AdapterFactory): void {
    this.factories.set(type, factory);
  }

  // ── Adapter CRUD ─────────────────────────────────────────────────────────────

  /**
   * Add a new adapter from config.
   * Creates the instance via the registered factory for its type.
   * Returns the assigned adapter id.
   */
  async add(config: AdapterConfig): Promise<string> {
    const id = config.id || uuid();
    config.id = id;

    if (this.entries.has(id)) {
      throw new Error(`Adapter "${id}" already exists`);
    }

    const factory = this.factories.get(config.type);
    if (!factory) {
      throw new Error(
        `No factory registered for adapter type "${config.type}". ` +
        `Registered types: ${[...this.factories.keys()].join(', ') || 'none'}`,
      );
    }

    const adapter = factory(config);
    await adapter.initialize(config);

    this.entries.set(id, { config, adapter });

    // Auto-start if enabled
    if (config.enabled) {
      try {
        await adapter.start();
      } catch (err) {
        console.error(`[AdapterRegistry] Failed to auto-start adapter "${id}":`, err);
      }
    }

    return id;
  }

  /**
   * Add an already-instantiated adapter (for testing or manual wiring).
   */
  async addInstance(adapter: DeviceAdapter, config: AdapterConfig): Promise<string> {
    const id = config.id || adapter.id;
    config.id = id;

    if (this.entries.has(id)) {
      throw new Error(`Adapter "${id}" already exists`);
    }

    await adapter.initialize(config);
    this.entries.set(id, { config, adapter });

    if (config.enabled) {
      try {
        await adapter.start();
      } catch (err) {
        console.error(`[AdapterRegistry] Failed to auto-start adapter "${id}":`, err);
      }
    }

    return id;
  }

  /**
   * Remove an adapter. Stops it first if running.
   */
  async remove(id: string): Promise<void> {
    const entry = this.entries.get(id);
    if (!entry) throw new Error(`Adapter "${id}" not found`);

    try {
      await entry.adapter.destroy();
    } catch (err) {
      console.warn(`[AdapterRegistry] Error destroying adapter "${id}":`, err);
    }

    this.entries.delete(id);
  }

  // ── Lifecycle ────────────────────────────────────────────────────────────────

  async start(id: string): Promise<void> {
    const entry = this.getEntry(id);
    await entry.adapter.start();
  }

  async stop(id: string): Promise<void> {
    const entry = this.getEntry(id);
    await entry.adapter.stop();
  }

  /**
   * Hot-reload: stop the old adapter, create a new one from updated config,
   * initialize, and start.  If anything fails the old state is not restored
   * (caller should re-add with the old config).
   */
  async reload(id: string, newConfig: AdapterConfig): Promise<void> {
    const oldEntry = this.entries.get(id);
    if (oldEntry) {
      try {
        await oldEntry.adapter.destroy();
      } catch {
        // best-effort
      }
      this.entries.delete(id);
    }

    newConfig.id = id;
    await this.add(newConfig);
  }

  // ── Query ────────────────────────────────────────────────────────────────────

  getAdapter(id: string): DeviceAdapter | undefined {
    return this.entries.get(id)?.adapter;
  }

  getConfig(id: string): AdapterConfig | undefined {
    return this.entries.get(id)?.config;
  }

  getAll(): AdapterStatusInfo[] {
    return [...this.entries.values()].map((e) => e.adapter.getStatus());
  }

  getByType(type: AdapterType): AdapterStatusInfo[] {
    return this.getAll().filter((s) => s.type === type);
  }

  // ── Internals ────────────────────────────────────────────────────────────────

  private getEntry(id: string): RegistryEntry {
    const entry = this.entries.get(id);
    if (!entry) throw new Error(`Adapter "${id}" not found`);
    return entry;
  }
}

// ── Singleton ──────────────────────────────────────────────────────────────────

let _registry: AdapterRegistry | null = null;

/** Get or create the global adapter registry. */
export function getRegistry(): AdapterRegistry {
  if (!_registry) {
    _registry = new AdapterRegistry();
  }
  return _registry;
}

/** Reset the singleton (for testing). */
export function resetRegistry(): void {
  _registry = null;
}

/**
 * DICOM Adapter - C-STORE SCP / C-FIND SCU / C-MOVE SCU
 *
 * Provides standard DICOM networking for receiving images from
 * ophthalmic devices (Zeiss OCT, Heidelberg Spectralis, etc.)
 *
 * NOTE: This is a simplified implementation suitable for integration.
 * For production, consider a battle-tested DICOM library like dcmjs-dimse
 * or orthanc as an external service.
 */

import { join } from 'path';
import { mkdir, writeFile } from 'fs/promises';
import { BaseAdapter } from './base';
import {
  type AdapterConfig,
  type InboundImageData,
  type PatientCriteria,
  type PatientQueryResult,
  type StudyCriteria,
  type StudyQueryResult,
} from './types';

/**
 * Minimal DICOM tag parser for extracting metadata from raw DICOM files.
 * Handles the most common tags needed for ophthalmic imaging.
 */
const DICOM_TAGS: Record<string, string> = {
  '00100010': 'patientName',
  '00100020': 'patientId',
  '00100030': 'patientBirthDate',
  '00100040': 'patientSex',
  '00080020': 'studyDate',
  '00080030': 'studyTime',
  '0020000D': 'studyInstanceUid',
  '0020000E': 'seriesInstanceUid',
  '00080018': 'sopInstanceUid',
  '00080060': 'modality',
  '00180015': 'bodyPartExamined',
  '00200010': 'studyId',
  '00080070': 'manufacturer',
  '00081090': 'modelName',
  '00280010': 'rows',
  '00280011': 'columns',
  '00280100': 'bitsAllocated',
  '00080008': 'imageType',
};

function parseDicomMetadata(buffer: Buffer): Record<string, unknown> {
  const meta: Record<string, unknown> = {};

  // DICOM preamble is 128 bytes + "DICM" magic
  if (buffer.length < 132) return meta;
  const magic = buffer.toString('ascii', 128, 132);
  if (magic !== 'DICM') return meta;

  let offset = 132;

  // Skip meta information group (0002,xxxx) - read until we hit a non-0002 group
  while (offset < buffer.length - 4) {
    const group = buffer.readUInt16LE(offset);
    const element = buffer.readUInt16LE(offset + 2);
    const tag = `${group.toString(16).padStart(4, '0')}${element.toString(16).padStart(4, '0')}`;

    // VR
    let vr: string;
    let vrOffset: number;
    let valueLength: number;

    if (group === 0x0002) {
      // Explicit VR for meta group
      vr = buffer.toString('ascii', offset + 4, offset + 6);
      vrOffset = offset + 4;
      if (['OB', 'OW', 'OF', 'SQ', 'UC', 'UN', 'UR', 'UT'].includes(vr)) {
        valueLength = buffer.readUInt32LE(offset + 8);
        offset += 12;
      } else {
        valueLength = buffer.readUInt16LE(offset + 6);
        offset += 8;
      }
    } else {
      // Implicit VR for data elements - assume UN
      vr = 'UN';
      vrOffset = offset + 4;
      valueLength = buffer.readUInt32LE(offset + 4);
      offset += 8;
    }

    if (valueLength === 0xffffffff) {
      // Undefined length - skip (sequences, etc.)
      break;
    }

    const tagName = DICOM_TAGS[tag];
    if (tagName && valueLength > 0 && offset + valueLength <= buffer.length) {
      const value = buffer.toString('ascii', offset, offset + valueLength).trim();
      meta[tagName] = value;
    }

    offset += valueLength;
    if (offset > buffer.length) break;
  }

  return meta;
}

export class DicomAdapter extends BaseAdapter {
  private server: ReturnType<typeof Bun.serve> | null = null;
  private storagePath: string;
  private receivedImages: Map<string, { path: string; metadata: Record<string, unknown> }> = new Map();

  constructor(id?: string) {
    super('dicom', id);
  }

  // ── Lifecycle hooks ──────────────────────────────────────────────────────────

  protected async onInitialize(config: AdapterConfig): Promise<void> {
    this.storagePath = join(process.cwd(), 'data', 'dicom', config.id);
    await mkdir(this.storagePath, { recursive: true });
  }

  protected async onStart(): Promise<void> {
    const dicomConfig = this.config.dicom;
    if (!dicomConfig) {
      throw new Error('[DicomAdapter] Missing dicom configuration');
    }

    // Start a simplified DICOM C-STORE SCP server
    // In production, use a proper DICOM library like dcmjs-dimse
    this.server = Bun.serve({
      port: dicomConfig.port,
      hostname: '0.0.0.0',

      async fetch(req) {
        // DICOMweb STOW-RS endpoint for receiving DICOM instances
        const url = new URL(req.url);

        if (url.pathname === '/stow-rs' && req.method === 'POST') {
          try {
            const formData = await req.formData();
            const files = formData.getAll('file') as File[];

            for (const file of files) {
              const buffer = Buffer.from(await file.arrayBuffer());
              const metadata = parseDicomMetadata(buffer);
              const filename = (metadata.sopInstanceUid as string) || `${Date.now()}.dcm`;
              const filePath = join(storagePath, `${filename}.dcm`);

              await writeFile(filePath, buffer);

              receivedImages.set(filename, { path: filePath, metadata });
              this.events.emit('image:received', {
                id: filename,
                metadata,
                path: filePath,
              });
            }

            return new Response(
              JSON.stringify({ success: true, count: files.length }),
              { status: 200, headers: { 'Content-Type': 'application/json' } },
            );
          } catch (err) {
            return new Response(
              JSON.stringify({ success: false, error: String(err) }),
              { status: 500, headers: { 'Content-Type': 'application/json' } },
            );
          }
        }

        // QIDO-RS endpoint for queries
        if (url.pathname === '/qido-rs' && req.method === 'GET') {
          const results = [...receivedImages.values()].map((img) => img.metadata);
          return new Response(
            JSON.stringify({ success: true, data: results }),
            { status: 200, headers: { 'Content-Type': 'application/json' } },
          );
        }

        return new Response('Not Found', { status: 404 });
      },
    });

    const _storagePath = this.storagePath;
    const _receivedImages = this.receivedImages;
    const _events = this.events;

    console.log(
      `[DicomAdapter] C-STORE SCP listening on port ${dicomConfig.port} ` +
      `(AE Title: ${dicomConfig.aeTitle})`,
    );
  }

  protected async onStop(): Promise<void> {
    if (this.server) {
      this.server.stop();
      this.server = null;
    }
    console.log('[DicomAdapter] Stopped');
  }

  protected async onDestroy(): Promise<void> {
    await this.onStop();
    this.receivedImages.clear();
  }

  // ── Data operations ──────────────────────────────────────────────────────────

  async receiveImage(image: InboundImageData): Promise<void> {
    await super.receiveImage(image);

    const metadata = parseDicomMetadata(image.buffer);
    const filename =
      (metadata.sopInstanceUid as string) ||
      image.filename ||
      `${Date.now()}.dcm`;

    const filePath = join(this.storagePath, `${filename}.dcm`);
    await writeFile(filePath, image.buffer);

    this.receivedImages.set(filename, { path: filePath, metadata });

    this.events.emit('image:received', {
      id: filename,
      metadata,
      path: filePath,
    });
  }

  async queryPatient(criteria: PatientCriteria): Promise<PatientQueryResult[]> {
    const results: PatientQueryResult[] = [];
    const seen = new Set<string>();

    for (const img of this.receivedImages.values()) {
      const m = img.metadata;
      const mrn = m.patientId as string | undefined;

      if (!mrn || seen.has(mrn)) continue;

      if (criteria.mrn && mrn !== criteria.mrn) continue;
      if (
        criteria.name &&
        !(m.patientName as string || '').toLowerCase().includes(criteria.name.toLowerCase())
      )
        continue;

      seen.add(mrn);
      results.push({
        mrn,
        name: (m.patientName as string) || 'Unknown',
        birthDate: m.patientBirthDate as string | undefined,
        gender: m.patientSex as string | undefined,
      });
    }

    return results;
  }

  async queryStudies(criteria: StudyCriteria): Promise<StudyQueryResult[]> {
    const results: StudyQueryResult[] = [];
    const seen = new Set<string>();

    for (const img of this.receivedImages.values()) {
      const m = img.metadata;
      const studyUid = m.studyInstanceUid as string | undefined;

      if (!studyUid || seen.has(studyUid)) continue;

      if (criteria.studyInstanceUid && studyUid !== criteria.studyInstanceUid) continue;
      if (criteria.modality && (m.modality as string) !== criteria.modality) continue;

      seen.add(studyUid);
      results.push({
        studyInstanceUid: studyUid,
        patientMrn: (m.patientId as string) || '',
        studyDate: (m.studyDate as string) || '',
        modality: (m.modality as string) || 'OT',
        description: (m.bodyPartExamined as string) || undefined,
      });
    }

    return results;
  }
}

/**
 * REST API Adapter
 *
 * Provides a REST endpoint for uploading images from ophthalmic devices
 * that don't support DICOM or where DICOM is impractical.
 *
 * Also supports webhook callbacks to notify external systems when images
 * are received.
 */

import { join } from 'path';
import { mkdir, writeFile } from 'fs/promises';
import { BaseAdapter } from './base';
import {
  type AdapterConfig,
  type InboundImageData,
  type PatientCriteria,
  type PatientQueryResult,
  type StudyCriteria,
  type StudyQueryResult,
} from './types';

/** Result of processing an upload */
export interface UploadResult {
  id: string;
  filename: string;
  size: number;
  metadata: Record<string, unknown>;
}

export class RestAdapter extends BaseAdapter {
  private storagePath: string;
  private webhookUrl?: string;
  private webhookSecret?: string;
  private apiKey?: string;
  private receivedImages: Map<string, { path: string; metadata: Record<string, unknown> }> = new Map();

  constructor(id?: string) {
    super('rest', id);
  }

  // ── Lifecycle hooks ──────────────────────────────────────────────────────────

  protected async onInitialize(config: AdapterConfig): Promise<void> {
    this.storagePath = join(process.cwd(), 'data', 'rest', config.id);
    await mkdir(this.storagePath, { recursive: true });

    if (config.rest) {
      this.webhookUrl = config.rest.webhookUrl;
      this.webhookSecret = config.rest.webhookSecret;
      this.apiKey = config.rest.apiKey;
    }
  }

  protected async onStart(): Promise<void> {
    // REST adapter does not start its own server; it is mounted on the main Hono app.
    // The route handler is registered via the adapter routes module.
    console.log(`[RestAdapter] "${this.config.name}" ready to receive uploads`);
  }

  protected async onStop(): Promise<void> {
    console.log(`[RestAdapter] "${this.config.name}" stopped`);
  }

  protected async onDestroy(): Promise<void> {
    this.receivedImages.clear();
  }

  // ── Data operations ──────────────────────────────────────────────────────────

  /**
   * Process an uploaded file (called from the route handler).
   * Validates API key, stores the file, fires webhook.
   */
  async processUpload(
    file: { buffer: Buffer; filename: string; mimetype: string },
    metadata: Record<string, unknown> = {},
  ): Promise<UploadResult> {
    if (this._status !== 'running') {
      throw new Error(`[RestAdapter] Adapter is not running (status: ${this._status})`);
    }

    const id = `${Date.now()}-${file.filename}`;
    const filePath = join(this.storagePath, id);

    await writeFile(filePath, file.buffer);

    const fullMetadata = {
      ...metadata,
      originalFilename: file.filename,
      mimetype: file.mimetype,
      size: file.buffer.length,
      uploadedAt: new Date().toISOString(),
    };

    this.receivedImages.set(id, { path: filePath, metadata: fullMetadata });

    // Update base class counters
    this._lastImageAt = new Date().toISOString();
    this._imageCount++;

    this.events.emit('image:received', {
      id,
      metadata: fullMetadata,
      path: filePath,
    });

    // Fire webhook if configured
    if (this.webhookUrl) {
      this.fireWebhook(id, fullMetadata).catch((err) => {
        console.error(`[RestAdapter] Webhook failed for ${id}:`, err);
      });
    }

    return {
      id,
      filename: file.filename,
      size: file.buffer.length,
      metadata: fullMetadata,
    };
  }

  /**
   * Receive an image directly (e.g., from another adapter or internal pipeline).
   */
  async receiveImage(image: InboundImageData): Promise<void> {
    await super.receiveImage(image);

    const id = image.filename || `${Date.now()}`;
    const filePath = join(this.storagePath, id);

    await writeFile(filePath, image.buffer);

    this.receivedImages.set(id, { path: filePath, metadata: image.metadata });

    this.events.emit('image:received', {
      id,
      metadata: image.metadata,
      path: filePath,
    });
  }

  async queryPatient(criteria: PatientCriteria): Promise<PatientQueryResult[]> {
    const results: PatientQueryResult[] = [];
    const seen = new Set<string>();

    for (const img of this.receivedImages.values()) {
      const m = img.metadata;
      const mrn = (m.patientMrn as string) || (m.patientId as string) || undefined;

      if (!mrn || seen.has(mrn)) continue;

      if (criteria.mrn && mrn !== criteria.mrn) continue;
      if (
        criteria.name &&
        !(m.patientName as string || '').toLowerCase().includes(criteria.name.toLowerCase())
      )
        continue;

      seen.add(mrn);
      results.push({
        mrn,
        name: (m.patientName as string) || 'Unknown',
        birthDate: m.patientBirthDate as string | undefined,
        gender: m.patientSex as string | undefined,
      });
    }

    return results;
  }

  async queryStudies(criteria: StudyCriteria): Promise<StudyQueryResult[]> {
    const results: StudyQueryResult[] = [];
    const seen = new Set<string>();

    for (const img of this.receivedImages.values()) {
      const m = img.metadata;
      const studyUid = (m.studyInstanceUid as string) || (m.studyId as string) || undefined;

      if (!studyUid || seen.has(studyUid)) continue;

      if (criteria.studyInstanceUid && studyUid !== criteria.studyInstanceUid) continue;
      if (criteria.modality && (m.modality as string) !== criteria.modality) continue;

      seen.add(studyUid);
      results.push({
        studyInstanceUid: studyUid,
        patientMrn: (m.patientMrn as string) || (m.patientId as string) || '',
        studyDate: (m.studyDate as string) || '',
        modality: (m.modality as string) || 'OT',
      });
    }

    return results;
  }

  // ── Webhook ──────────────────────────────────────────────────────────────────

  private async fireWebhook(
    imageId: string,
    metadata: Record<string, unknown>,
  ): Promise<void> {
    if (!this.webhookUrl) return;

    const payload = JSON.stringify({
      event: 'image.received',
      adapterId: this.id,
      imageId,
      metadata,
      timestamp: new Date().toISOString(),
    });

    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };

    // HMAC-SHA256 signature if secret is configured
    if (this.webhookSecret) {
      const crypto = await import('crypto');
      const signature = crypto
        .createHmac('sha256', this.webhookSecret)
        .update(payload)
        .digest('hex');
      headers['X-Webhook-Signature'] = `sha256=${signature}`;
    }

    try {
      const response = await fetch(this.webhookUrl, {
        method: 'POST',
        headers,
        body: payload,
        signal: AbortSignal.timeout(10_000),
      });

      if (!response.ok) {
        console.warn(
          `[RestAdapter] Webhook returned ${response.status} for image ${imageId}`,
        );
      }
    } catch (err) {
      console.error(`[RestAdapter] Webhook request failed for image ${imageId}:`, err);
    }
  }

  /** Validate an incoming API key against the configured one. */
  validateApiKey(provided: string | undefined): boolean {
    if (!this.apiKey) return true; // no key configured = open access
    return provided === this.apiKey;
  }
}

/**
 * Adapter Management API Routes
 *
 * Provides endpoints for:
 *  - Listing all adapters
 *  - Adding / updating / removing adapters
 *  - Starting / stopping adapters
 *  - Uploading images via the REST adapter
 *  - Querying patients/studies across adapters
 */

import { Hono } from 'hono';
import { getRegistry } from '../adapters/registry';
import { DicomAdapter } from '../adapters/dicom';
import { RestAdapter } from '../adapters/rest';
import type { AdapterConfig, AdapterType } from '../adapters/types';

const adaptersRouter = new Hono();

// ── Register default factories on first import ─────────────────────────────────
const registry = getRegistry();

registry.registerFactory('dicom', (config) => {
  const adapter = new DicomAdapter(config.id);
  return adapter;
});

registry.registerFactory('rest', (config) => {
  const adapter = new RestAdapter(config.id);
  return adapter;
});

// ── List all adapters ──────────────────────────────────────────────────────────
adaptersRouter.get('/', (c) => {
  const all = registry.getAll();
  return c.json({ success: true, data: all });
});

// ── Get single adapter status ──────────────────────────────────────────────────
adaptersRouter.get('/:id', (c) => {
  const id = c.req.param('id');
  const adapter = registry.getAdapter(id);
  if (!adapter) {
    return c.json({ success: false, message: '适配器未找到' }, 404);
  }
  return c.json({ success: true, data: adapter.getStatus() });
});

// ── Add a new adapter ──────────────────────────────────────────────────────────
adaptersRouter.post('/', async (c) => {
  try {
    const body = await c.req.json();

    // Validate required fields
    if (!body.type || !body.name) {
      return c.json({ success: false, message: '缺少必填字段: type, name' }, 400);
    }

    const validTypes: AdapterType[] = ['dicom', 'rest', 'file', 'custom'];
    if (!validTypes.includes(body.type)) {
      return c.json(
        { success: false, message: `无效的适配器类型。支持: ${validTypes.join(', ')}` },
        400,
      );
    }

    const config: AdapterConfig = {
      id: body.id || crypto.randomUUID(),
      name: body.name,
      type: body.type,
      enabled: body.enabled ?? true,
      dicom: body.dicom,
      rest: body.rest,
      file: body.file,
      custom: body.custom,
    };

    const id = await registry.add(config);
    const adapter = registry.getAdapter(id);

    return c.json({ success: true, data: adapter?.getStatus() }, 201);
  } catch (err) {
    const message = err instanceof Error ? err.message : '添加适配器失败';
    return c.json({ success: false, message }, 500);
  }
});

// ── Update (hot-reload) an adapter ─────────────────────────────────────────────
adaptersRouter.put('/:id', async (c) => {
  try {
    const id = c.req.param('id');
    const body = await c.req.json();

    const existingConfig = registry.getConfig(id);
    if (!existingConfig) {
      return c.json({ success: false, message: '适配器未找到' }, 404);
    }

    // Merge existing config with updates
    const newConfig: AdapterConfig = {
      ...existingConfig,
      ...body,
      id, // prevent id change
    };

    await registry.reload(id, newConfig);
    const adapter = registry.getAdapter(id);

    return c.json({ success: true, data: adapter?.getStatus() });
  } catch (err) {
    const message = err instanceof Error ? err.message : '更新适配器失败';
    return c.json({ success: false, message }, 500);
  }
});

// ── Remove an adapter ──────────────────────────────────────────────────────────
adaptersRouter.delete('/:id', async (c) => {
  try {
    const id = c.req.param('id');
    await registry.remove(id);
    return c.json({ success: true, message: '适配器已删除' });
  } catch (err) {
    const message = err instanceof Error ? err.message : '删除适配器失败';
    return c.json({ success: false, message }, 500);
  }
});

// ── Start an adapter ───────────────────────────────────────────────────────────
adaptersRouter.post('/:id/start', async (c) => {
  try {
    const id = c.req.param('id');
    await registry.start(id);
    const adapter = registry.getAdapter(id);
    return c.json({ success: true, data: adapter?.getStatus() });
  } catch (err) {
    const message = err instanceof Error ? err.message : '启动适配器失败';
    return c.json({ success: false, message }, 500);
  }
});

// ── Stop an adapter ────────────────────────────────────────────────────────────
adaptersRouter.post('/:id/stop', async (c) => {
  try {
    const id = c.req.param('id');
    await registry.stop(id);
    const adapter = registry.getAdapter(id);
    return c.json({ success: true, data: adapter?.getStatus() });
  } catch (err) {
    const message = err instanceof Error ? err.message : '停止适配器失败';
    return c.json({ success: false, message }, 500);
  }
});

// ── Upload image via REST adapter ──────────────────────────────────────────────
adaptersRouter.post('/:id/upload', async (c) => {
  try {
    const id = c.req.param('id');
    const adapter = registry.getAdapter(id);

    if (!adapter) {
      return c.json({ success: false, message: '适配器未找到' }, 404);
    }

    if (!(adapter instanceof RestAdapter)) {
      return c.json({ success: false, message: '只有 REST 适配器支持文件上传' }, 400);
    }

    if (adapter.status !== 'running') {
      return c.json({ success: false, message: '适配器未运行' }, 400);
    }

    // Validate API key
    const apiKey = c.req.header('X-API-Key');
    if (!adapter.validateApiKey(apiKey)) {
      return c.json({ success: false, message: '无效的 API Key' }, 401);
    }

    const contentType = c.req.header('Content-Type') || '';

    if (contentType.includes('multipart/form-data')) {
      const formData = await c.req.formData();
      const file = formData.get('file') as File | null;

      if (!file) {
        return c.json({ success: false, message: '请选择文件' }, 400);
      }

      // Extract optional metadata from form fields
      const metadata: Record<string, unknown> = {};
      for (const [key, value] of formData.entries()) {
        if (key !== 'file') {
          try {
            metadata[key] = JSON.parse(value as string);
          } catch {
            metadata[key] = value;
          }
        }
      }

      const result = await adapter.processUpload(
        {
          buffer: Buffer.from(await file.arrayBuffer()),
          filename: file.name,
          mimetype: file.type || 'application/octet-stream',
        },
        metadata,
      );

      return c.json({ success: true, data: result }, 201);
    }

    // Raw body upload
    const buffer = Buffer.from(await c.req.arrayBuffer());
    const filename = c.req.header('X-Filename') || `upload-${Date.now()}`;

    const result = await adapter.processUpload(
      {
        buffer,
        filename,
        mimetype: contentType || 'application/octet-stream',
      },
      {},
    );

    return c.json({ success: true, data: result }, 201);
  } catch (err) {
    const message = err instanceof Error ? err.message : '上传失败';
    return c.json({ success: false, message }, 500);
  }
});

// ── Batch upload ───────────────────────────────────────────────────────────────
adaptersRouter.post('/:id/upload-batch', async (c) => {
  try {
    const id = c.req.param('id');
    const adapter = registry.getAdapter(id);

    if (!adapter || !(adapter instanceof RestAdapter)) {
      return c.json({ success: false, message: '只有 REST 适配器支持批量上传' }, 400);
    }

    if (adapter.status !== 'running') {
      return c.json({ success: false, message: '适配器未运行' }, 400);
    }

    const apiKey = c.req.header('X-API-Key');
    if (!adapter.validateApiKey(apiKey)) {
      return c.json({ success: false, message: '无效的 API Key' }, 401);
    }

    const formData = await c.req.formData();
    const files = formData.getAll('file') as File[];

    if (files.length === 0) {
      return c.json({ success: false, message: '请选择文件' }, 400);
    }

    const results = [];
    for (const file of files) {
      const result = await adapter.processUpload(
        {
          buffer: Buffer.from(await file.arrayBuffer()),
          filename: file.name,
          mimetype: file.type || 'application/octet-stream',
        },
        {},
      );
      results.push(result);
    }

    return c.json({ success: true, data: results, count: results.length }, 201);
  } catch (err) {
    const message = err instanceof Error ? err.message : '批量上传失败';
    return c.json({ success: false, message }, 500);
  }
});

// ── Query patients across adapters ─────────────────────────────────────────────
adaptersRouter.get('/query/patients', async (c) => {
  const mrn = c.req.query('mrn');
  const name = c.req.query('name');

  const allResults: Array<{ adapterId: string; patients: Awaited<ReturnType<RestAdapter['queryPatient']>> }> = [];

  for (const info of registry.getAll()) {
    if (info.status !== 'running') continue;
    const adapter = registry.getAdapter(info.id);
    if (!adapter) continue;

    try {
      const patients = await adapter.queryPatient({ mrn, name });
      if (patients.length > 0) {
        allResults.push({ adapterId: info.id, patients });
      }
    } catch {
      // skip adapters that fail to query
    }
  }

  return c.json({ success: true, data: allResults });
});

// ── Query studies across adapters ──────────────────────────────────────────────
adaptersRouter.get('/query/studies', async (c) => {
  const patientMrn = c.req.query('patientMrn');
  const modality = c.req.query('modality');

  const allResults: Array<{ adapterId: string; studies: Awaited<ReturnType<RestAdapter['queryStudies']>> }> = [];

  for (const info of registry.getAll()) {
    if (info.status !== 'running') continue;
    const adapter = registry.getAdapter(info.id);
    if (!adapter) continue;

    try {
      const studies = await adapter.queryStudies({ patientMrn, modality });
      if (studies.length > 0) {
        allResults.push({ adapterId: info.id, studies });
      }
    } catch {
      // skip
    }
  }

  return c.json({ success: true, data: allResults });
});

export default adaptersRouter;

