import { describe, test, expect, beforeEach, afterEach } from 'bun:test';
import { AdapterEventEmitter } from '../types';

describe('AdapterEventEmitter', () => {
  let emitter: AdapterEventEmitter;

  beforeEach(() => {
    emitter = new AdapterEventEmitter();
  });

  test('should register and emit events', () => {
    let received: any = null;
    emitter.on('image:received', (data) => {
      received = data;
    });

    emitter.emit('image:received', { id: 'test-1' });
    expect(received).toEqual({ id: 'test-1' });
  });

  test('should support multiple listeners', () => {
    const calls: string[] = [];
    emitter.on('adapter:started', () => calls.push('a'));
    emitter.on('adapter:started', () => calls.push('b'));

    emitter.emit('adapter:started', {});
    expect(calls).toEqual(['a', 'b']);
  });

  test('should unsubscribe via returned function', () => {
    const calls: number[] = [];
    const unsub = emitter.on('adapter:status', () => calls.push(1));

    emitter.emit('adapter:status', {});
    expect(calls).toHaveLength(1);

    unsub();
    emitter.emit('adapter:status', {});
    expect(calls).toHaveLength(1);
  });

  test('should unsubscribe via off()', () => {
    const calls: number[] = [];
    const listener = () => calls.push(1);
    emitter.on('adapter:error', listener);

    emitter.emit('adapter:error', {});
    expect(calls).toHaveLength(1);

    emitter.off('adapter:error', listener);
    emitter.emit('adapter:error', {});
    expect(calls).toHaveLength(1);
  });

  test('should remove all listeners for a specific event', () => {
    const calls: string[] = [];
    emitter.on('image:received', () => calls.push('img'));
    emitter.on('adapter:error', () => calls.push('err'));

    emitter.removeAllListeners('image:received');
    emitter.emit('image:received', {});
    emitter.emit('adapter:error', {});

    expect(calls).toEqual(['err']);
  });

  test('should remove all listeners when no event specified', () => {
    const calls: string[] = [];
    emitter.on('image:received', () => calls.push('img'));
    emitter.on('adapter:error', () => calls.push('err'));

    emitter.removeAllListeners();
    emitter.emit('image:received', {});
    emitter.emit('adapter:error', {});

    expect(calls).toEqual([]);
  });

  test('should not throw if listener throws', () => {
    emitter.on('image:received', () => {
      throw new Error('boom');
    });

    // Should not throw
    expect(() => emitter.emit('image:received', {})).not.toThrow();
  });
});

import { describe, test, expect, beforeEach, afterEach } from 'bun:test';
import { getRegistry, resetRegistry } from '../registry';
import { BaseAdapter } from '../base';
import type { AdapterConfig, DeviceAdapter } from '../types';

// ── Test adapter implementation ────────────────────────────────────────────────

class TestAdapter extends BaseAdapter {
  public initCalled = false;
  public startCalled = false;
  public stopCalled = false;
  public destroyCalled = false;
  public receivedImages: any[] = [];

  constructor(id?: string) {
    super('custom', id);
  }

  protected async onInitialize(_config: AdapterConfig): Promise<void> {
    this.initCalled = true;
  }

  protected async onStart(): Promise<void> {
    this.startCalled = true;
  }

  protected async onStop(): Promise<void> {
    this.stopCalled = true;
  }

  protected async onDestroy(): Promise<void> {
    this.destroyCalled = true;
  }

  async receiveImage(image: any): Promise<void> {
    await super.receiveImage(image);
    this.receivedImages.push(image);
  }
}

// ── Tests ──────────────────────────────────────────────────────────────────────

describe('AdapterRegistry', () => {
  beforeEach(() => {
    resetRegistry();
  });

  test('should register a factory and create adapters', async () => {
    const registry = getRegistry();
    registry.registerFactory('custom', (config) => new TestAdapter(config.id));

    const id = await registry.add({
      id: 'test-1',
      name: 'Test Adapter',
      type: 'custom',
      enabled: false,
    });

    expect(id).toBe('test-1');
    const adapter = registry.getAdapter('test-1');
    expect(adapter).toBeDefined();
    expect(adapter!.type).toBe('custom');
    expect(adapter!.status).toBe('idle');
  });

  test('should auto-start enabled adapters', async () => {
    const registry = getRegistry();
    registry.registerFactory('custom', (config) => new TestAdapter(config.id));

    await registry.add({
      id: 'test-auto',
      name: 'Auto Start',
      type: 'custom',
      enabled: true,
    });

    const adapter = registry.getAdapter('test-auto') as TestAdapter;
    expect(adapter.status).toBe('running');
    expect(adapter.startCalled).toBe(true);
  });

  test('should throw when adding duplicate adapter id', async () => {
    const registry = getRegistry();
    registry.registerFactory('custom', (config) => new TestAdapter(config.id));

    await registry.add({
      id: 'dup',
      name: 'Dup',
      type: 'custom',
      enabled: false,
    });

    expect(
      registry.add({ id: 'dup', name: 'Dup2', type: 'custom', enabled: false }),
    ).rejects.toThrow('already exists');
  });

  test('should throw when no factory registered for type', async () => {
    const registry = getRegistry();

    expect(
      registry.add({ id: 'x', name: 'X', type: 'dicom', enabled: false }),
    ).rejects.toThrow('No factory registered');
  });

  test('should start and stop adapters', async () => {
    const registry = getRegistry();
    registry.registerFactory('custom', (config) => new TestAdapter(config.id));

    await registry.add({
      id: 'lifecycle',
      name: 'Lifecycle',
      type: 'custom',
      enabled: false,
    });

    await registry.start('lifecycle');
    const adapter = registry.getAdapter('lifecycle') as TestAdapter;
    expect(adapter.status).toBe('running');
    expect(adapter.startCalled).toBe(true);

    await registry.stop('lifecycle');
    expect(adapter.status).toBe('idle');
    expect(adapter.stopCalled).toBe(true);
  });

  test('should remove adapters', async () => {
    const registry = getRegistry();
    registry.registerFactory('custom', (config) => new TestAdapter(config.id));

    await registry.add({
      id: 'removable',
      name: 'Removable',
      type: 'custom',
      enabled: false,
    });

    await registry.remove('removable');
    expect(registry.getAdapter('removable')).toBeUndefined();
  });

  test('should reload adapters (hot-reload)', async () => {
    const registry = getRegistry();
    registry.registerFactory('custom', (config) => new TestAdapter(config.id));

    await registry.add({
      id: 'reload-me',
      name: 'Original',
      type: 'custom',
      enabled: false,
    });

    const originalAdapter = registry.getAdapter('reload-me') as TestAdapter;

    await registry.reload('reload-me', {
      id: 'reload-me',
      name: 'Updated',
      type: 'custom',
      enabled: false,
    });

    const newAdapter = registry.getAdapter('reload-me') as TestAdapter;
    expect(newAdapter).not.toBe(originalAdapter);
    expect(newAdapter.initCalled).toBe(true);
    expect(originalAdapter.destroyCalled).toBe(true);
  });

  test('should list all adapters', async () => {
    const registry = getRegistry();
    registry.registerFactory('custom', (config) => new TestAdapter(config.id));

    await registry.add({ id: 'a', name: 'A', type: 'custom', enabled: false });
    await registry.add({ id: 'b', name: 'B', type: 'custom', enabled: false });

    const all = registry.getAll();
    expect(all).toHaveLength(2);
    expect(all.map((a) => a.id)).toContain('a');
    expect(all.map((a) => a.id)).toContain('b');
  });

  test('should filter adapters by type', async () => {
    const registry = getRegistry();
    registry.registerFactory('custom', (config) => new TestAdapter(config.id));
    registry.registerFactory('rest', (config) => {
      const a = new TestAdapter(config.id);
      (a as any).type = 'rest';
      return a;
    });

    await registry.add({ id: 'c1', name: 'Custom 1', type: 'custom', enabled: false });
    await registry.add({ id: 'r1', name: 'Rest 1', type: 'rest', enabled: false });

    const customs = registry.getByType('custom');
    expect(customs).toHaveLength(1);
    expect(customs[0].id).toBe('c1');
  });

  test('should get adapter config', async () => {
    const registry = getRegistry();
    registry.registerFactory('custom', (config) => new TestAdapter(config.id));

    const config: AdapterConfig = {
      id: 'cfg-test',
      name: 'Config Test',
      type: 'custom',
      enabled: false,
      custom: { foo: 'bar' },
    };

    await registry.add(config);
    const retrieved = registry.getConfig('cfg-test');
    expect(retrieved?.name).toBe('Config Test');
    expect(retrieved?.custom?.foo).toBe('bar');
  });

  test('addInstance should work with pre-created adapters', async () => {
    const registry = getRegistry();
    const adapter = new TestAdapter('manual');

    await registry.addInstance(adapter, {
      id: 'manual',
      name: 'Manual',
      type: 'custom',
      enabled: false,
    });

    expect(registry.getAdapter('manual')).toBe(adapter);
    expect(adapter.initCalled).toBe(true);
  });
});

import { describe, test, expect, beforeEach, afterEach } from 'bun:test';
import { RestAdapter } from '../rest';
import type { AdapterConfig } from '../types';
import { existsSync } from 'fs';
import { rm } from 'fs/promises';

describe('RestAdapter', () => {
  let adapter: RestAdapter;
  const testConfig: AdapterConfig = {
    id: 'rest-test',
    name: 'Test REST Adapter',
    type: 'rest',
    enabled: false,
    rest: {
      apiKey: 'test-key-123',
      webhookUrl: undefined,
    },
  };

  beforeEach(async () => {
    adapter = new RestAdapter('rest-test');
    await adapter.initialize(testConfig);
  });

  afterEach(async () => {
    try {
      await adapter.destroy();
    } catch {
      // ignore
    }
    // Clean up test data
    const storagePath = `${process.cwd()}/data/rest/rest-test`;
    if (existsSync(storagePath)) {
      await rm(storagePath, { recursive: true, force: true });
    }
  });

  test('should initialize with correct status', () => {
    expect(adapter.status).toBe('idle');
    expect(adapter.id).toBe('rest-test');
    expect(adapter.type).toBe('rest');
  });

  test('should start and stop', async () => {
    await adapter.start();
    expect(adapter.status).toBe('running');

    await adapter.stop();
    expect(adapter.status).toBe('idle');
  });

  test('should reject image upload when not running', async () => {
    const image = {
      buffer: Buffer.from('test'),
      filename: 'test.jpg',
      mimetype: 'image/jpeg',
    };

    expect(adapter.processUpload(image)).rejects.toThrow('not running');
  });

  test('should process image upload when running', async () => {
    await adapter.start();

    const image = {
      buffer: Buffer.from([0xff, 0xd8, 0xff, 0xe0]), // fake JPEG header
      filename: 'fundus-photo.jpg',
      mimetype: 'image/jpeg',
    };

    const metadata = {
      patientMrn: 'MRN001',
      patientName: 'Test Patient',
      studyDate: '2024-01-15',
      modality: 'fundus',
    };

    const result = await adapter.processUpload(image, metadata);

    expect(result.filename).toBe('fundus-photo.jpg');
    expect(result.size).toBe(4);
    expect(result.metadata.patientMrn).toBe('MRN001');
    expect(result.id).toBeDefined();
  });

  test('should query patients after upload', async () => {
    await adapter.start();

    await adapter.processUpload(
      { buffer: Buffer.from('img1'), filename: 'img1.jpg', mimetype: 'image/jpeg' },
      { patientMrn: 'P001', patientName: 'Alice' },
    );

    await adapter.processUpload(
      { buffer: Buffer.from('img2'), filename: 'img2.jpg', mimetype: 'image/jpeg' },
      { patientMrn: 'P001', patientName: 'Alice' },
    );

    await adapter.processUpload(
      { buffer: Buffer.from('img3'), filename: 'img3.jpg', mimetype: 'image/jpeg' },
      { patientMrn: 'P002', patientName: 'Bob' },
    );

    const allPatients = await adapter.queryPatient({});
    expect(allPatients).toHaveLength(2);
    expect(allPatients.map((p) => p.mrn)).toContain('P001');
    expect(allPatients.map((p) => p.mrn)).toContain('P002');

    const filtered = await adapter.queryPatient({ mrn: 'P001' });
    expect(filtered).toHaveLength(1);
    expect(filtered[0].name).toBe('Alice');
  });

  test('should query studies after upload', async () => {
    await adapter.start();

    await adapter.processUpload(
      { buffer: Buffer.from('img1'), filename: 'img1.jpg', mimetype: 'image/jpeg' },
      { patientMrn: 'P001', studyInstanceUid: 'S001', studyDate: '2024-01-01', modality: 'OCT' },
    );

    await adapter.processUpload(
      { buffer: Buffer.from('img2'), filename: 'img2.jpg', mimetype: 'image/jpeg' },
      { patientMrn: 'P001', studyInstanceUid: 'S002', studyDate: '2024-02-01', modality: 'fundus' },
    );

    const allStudies = await adapter.queryStudies({});
    expect(allStudies).toHaveLength(2);

    const octStudies = await adapter.queryStudies({ modality: 'OCT' });
    expect(octStudies).toHaveLength(1);
    expect(octStudies[0].studyDate).toBe('2024-01-01');
  });

  test('should validate API key', () => {
    expect(adapter.validateApiKey('test-key-123')).toBe(true);
    expect(adapter.validateApiKey('wrong-key')).toBe(false);
    expect(adapter.validateApiKey(undefined)).toBe(false);
  });

  test('should accept any key when no key configured', async () => {
    const noKeyAdapter = new RestAdapter('no-key');
    await noKeyAdapter.initialize({
      id: 'no-key',
      name: 'No Key',
      type: 'rest',
      enabled: false,
    });

    expect(noKeyAdapter.validateApiKey('anything')).toBe(true);
    expect(noKeyAdapter.validateApiKey(undefined)).toBe(true);

    await noKeyAdapter.destroy();
  });

  test('should emit events on image receive', async () => {
    await adapter.start();

    const events: any[] = [];
    adapter.events.on('image:received', (data) => events.push(data));

    await adapter.processUpload(
      { buffer: Buffer.from('test'), filename: 'test.jpg', mimetype: 'image/jpeg' },
      {},
    );

    expect(events).toHaveLength(1);
    expect(events[0].id).toBeDefined();
    expect(events[0].metadata).toBeDefined();
    expect(events[0].path).toBeDefined();
  });

  test('should report status correctly', async () => {
    await adapter.start();

    await adapter.processUpload(
      { buffer: Buffer.from('img1'), filename: 'img1.jpg', mimetype: 'image/jpeg' },
      {},
    );

    const status = adapter.getStatus();
    expect(status.id).toBe('rest-test');
    expect(status.name).toBe('Test REST Adapter');
    expect(status.type).toBe('rest');
    expect(status.status).toBe('running');
    expect(status.imageCount).toBe(1);
    expect(status.uptime).toBeGreaterThanOrEqual(0);
  });

  test('should sanitize config in status (hide secrets)', async () => {
    const status = adapter.getStatus();
    expect(status.config.rest?.apiKey).toBe('***');
  });
});

import { describe, test, expect, beforeEach, afterEach } from 'bun:test';
import { DicomAdapter } from '../dicom';
import type { AdapterConfig } from '../types';
import { existsSync } from 'fs';
import { rm } from 'fs/promises';

describe('DicomAdapter', () => {
  let adapter: DicomAdapter;
  const testPort = 11113; // Use non-standard port to avoid conflicts
  const testConfig: AdapterConfig = {
    id: 'dicom-test',
    name: 'Test DICOM Adapter',
    type: 'dicom',
    enabled: false,
    dicom: {
      aeTitle: 'PACS_TEST',
      port: testPort,
    },
  };

  beforeEach(async () => {
    adapter = new DicomAdapter('dicom-test');
    await adapter.initialize(testConfig);
  });

  afterEach(async () => {
    try {
      await adapter.destroy();
    } catch {
      // ignore
    }
    const storagePath = `${process.cwd()}/data/dicom/dicom-test`;
    if (existsSync(storagePath)) {
      await rm(storagePath, { recursive: true, force: true });
    }
  });

  test('should initialize with correct status', () => {
    expect(adapter.status).toBe('idle');
    expect(adapter.id).toBe('dicom-test');
    expect(adapter.type).toBe('dicom');
  });

  test('should start and stop DICOM server', async () => {
    await adapter.start();
    expect(adapter.status).toBe('running');

    await adapter.stop();
    expect(adapter.status).toBe('idle');
  });

  test('should reject image receive when not running', async () => {
    const image = {
      buffer: Buffer.from('not-dicom'),
      filename: 'test.dcm',
      format: 'dicom',
      metadata: {},
    };

    expect(adapter.receiveImage(image)).rejects.toThrow('not running');
  });

  test('should receive DICOM image when running', async () => {
    await adapter.start();

    // Create a minimal DICOM-like buffer (just enough to test storage)
    // Real DICOM has a 128-byte preamble + "DICM" magic
    const preamble = Buffer.alloc(128, 0);
    const magic = Buffer.from('DICM');
    const buffer = Buffer.concat([preamble, magic]);

    const image = {
      buffer,
      filename: 'test-image.dcm',
      format: 'dicom',
      metadata: { patientId: 'P001' },
    };

    await adapter.receiveImage(image);

    const status = adapter.getStatus();
    expect(status.imageCount).toBe(1);
    expect(status.lastImageAt).toBeDefined();
  });

  test('should query patients after receiving images', async () => {
    await adapter.start();

    // Create DICOM-like buffers with embedded metadata
    // For this test we'll use the receiveImage method which parses metadata
    const image1 = {
      buffer: Buffer.from('DICOM-fake-1'),
      filename: 'img1.dcm',
      format: 'dicom',
      metadata: {},
    };

    await adapter.receiveImage(image1);

    // Since our fake DICOM won't have parseable metadata, queryPatient returns empty
    const patients = await adapter.queryPatient({});
    expect(patients).toBeInstanceOf(Array);
  });

  test('should query studies', async () => {
    await adapter.start();

    const image = {
      buffer: Buffer.from('DICOM-fake'),
      filename: 'img.dcm',
      format: 'dicom',
      metadata: {},
    };

    await adapter.receiveImage(image);

    const studies = await adapter.queryStudies({});
    expect(studies).toBeInstanceOf(Array);
  });

  test('should emit events on image receive', async () => {
    await adapter.start();

    const events: any[] = [];
    adapter.events.on('image:received', (data) => events.push(data));

    await adapter.receiveImage({
      buffer: Buffer.from('DICOM-fake'),
      filename: 'test.dcm',
      format: 'dicom',
      metadata: {},
    });

    expect(events).toHaveLength(1);
    expect(events[0].id).toBeDefined();
  });

  test('should report status correctly', async () => {
    await adapter.start();

    const status = adapter.getStatus();
    expect(status.id).toBe('dicom-test');
    expect(status.name).toBe('Test DICOM Adapter');
    expect(status.type).toBe('dicom');
    expect(status.status).toBe('running');
    expect(status.imageCount).toBe(0);
  });

  test('should require dicom config to start', async () => {
    const noDicomAdapter = new DicomAdapter('no-dicom');
    await noDicomAdapter.initialize({
      id: 'no-dicom',
      name: 'No Dicom Config',
      type: 'dicom',
      enabled: false,
    });

    expect(noDicomAdapter.start()).rejects.toThrow('Missing dicom configuration');
    await noDicomAdapter.destroy();
  });
});

